// Extract alert from request body
const raw = $input.item.json.body || $input.item.json;

// Validate required fields
const required = ['source', 'alertType'];
const missing = required.filter(f => !raw[f]);
if (missing.length > 0) {
  throw new Error(`Missing required alert fields: ${missing.join(', ')}`);
}

// Normalize alert type to standard taxonomy
const alertTypeMappings = {
  'brute_force': 'BRUTE_FORCE',
  'bruteforce': 'BRUTE_FORCE',
  'login_failure': 'BRUTE_FORCE',
  'malware': 'MALWARE_DETECTED',
  'malware_detected': 'MALWARE_DETECTED',
  'ransomware': 'RANSOMWARE',
  'phishing': 'PHISHING',
  'data_exfiltration': 'DATA_EXFILTRATION',
  'exfiltration': 'DATA_EXFILTRATION',
  'lateral_movement': 'LATERAL_MOVEMENT',
  'privilege_escalation': 'PRIVILEGE_ESCALATION',
  'ddos': 'DDOS_ATTACK',
  'dos': 'DDOS_ATTACK',
  'sql_injection': 'WEB_ATTACK',
  'xss': 'WEB_ATTACK',
  'web_attack': 'WEB_ATTACK',
  'c2': 'C2_COMMUNICATION',
  'c2_communication': 'C2_COMMUNICATION',
  'unauthorized_access': 'UNAUTHORIZED_ACCESS'
};

const normalizedType = alertTypeMappings[raw.alertType?.toLowerCase()] || raw.alertType?.toUpperCase() || 'UNKNOWN';

// Normalize source
const sourceMap = {
  'splunk': 'SIEM',
  'qradar': 'SIEM',
  'sentinel': 'SIEM',
  'crowdstrike': 'EDR',
  'sentinelone': 'EDR',
  'defender': 'EDR',
  'paloalto': 'FIREWALL',
  'fortinet': 'FIREWALL',
  'cisco': 'FIREWALL',
  'snort': 'IDS',
  'suricata': 'IDS'
};

const sourceCategory = sourceMap[raw.source?.toLowerCase()] || 'UNKNOWN';

// Extract IPs safely
const sourceIP = raw.sourceIP || raw.src_ip || raw.attackerIP || null;
const destinationIP = raw.destinationIP || raw.dst_ip || raw.targetIP || null;

// Build normalized incident
const incident = {
  incidentId: `INC-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
  alertType: normalizedType,
  source: raw.source || 'unknown',
  sourceCategory,
  sourceIP,
  destinationIP,
  affectedHost: raw.affectedHost || raw.hostname || raw.host || null,
  affectedUser: raw.affectedUser || raw.username || raw.user || null,
  affectedAsset: raw.affectedAsset || raw.asset || null,
  rawLog: raw.rawLog || raw.message || raw.log || JSON.stringify(raw),
  originalTimestamp: raw.timestamp || new Date().toISOString(),
  receivedAt: new Date().toISOString(),
  tags: raw.tags || [],
  additionalContext: raw.context || {}
};

return { json: { incident } };

// Pull all enrichment sources
const incident = $('Normalize and Validate Alert').item.json.incident;
const vtResponse = $('Check IP on VirusTotal').item.json;
const abuseResponse = $('Check IP on AbuseIPDB').item.json;
const shodanResponse = $('Lookup Host on Shodan').item.json;

// Parse VirusTotal
let virusTotalData = { maliciousVotes: 0, suspiciousVotes: 0, harmlessVotes: 0, totalEngines: 0, country: 'Unknown', asOwner: 'Unknown' };
try {
  if (vtResponse && vtResponse.data?.attributes) {
    const attrs = vtResponse.data.attributes;
    const stats = attrs.last_analysis_stats || {};
    virusTotalData = {
      maliciousVotes: stats.malicious || 0,
      suspiciousVotes: stats.suspicious || 0,
      harmlessVotes: stats.harmless || 0,
      totalEngines: (stats.malicious || 0) + (stats.suspicious || 0) + (stats.harmless || 0) + (stats.undetected || 0),
      country: attrs.country || 'Unknown',
      asOwner: attrs.as_owner || 'Unknown',
      reputation: attrs.reputation || 0,
      lastAnalysisDate: attrs.last_analysis_date ? new Date(attrs.last_analysis_date * 1000).toISOString() : null
    };
  }
} catch (e) { console.log('VT parse error:', e.message); }

// Parse AbuseIPDB
let abuseIPData = { abuseConfidenceScore: 0, totalReports: 0, isWhitelisted: false, isp: 'Unknown', usageType: 'Unknown', countryCode: 'Unknown' };
try {
  if (abuseResponse && abuseResponse.data) {
    const d = abuseResponse.data;
    abuseIPData = {
      abuseConfidenceScore: d.abuseConfidenceScore || 0,
      totalReports: d.totalReports || 0,
      isWhitelisted: d.isWhitelisted || false,
      isp: d.isp || 'Unknown',
      usageType: d.usageType || 'Unknown',
      countryCode: d.countryCode || 'Unknown',
      lastReportedAt: d.lastReportedAt || null
    };
  }
} catch (e) { console.log('AbuseIPDB parse error:', e.message); }

// Parse Shodan
let shodanData = { openPorts: [], vulns: [], hostnames: [], os: 'Unknown', org: 'Unknown' };
try {
  if (shodanResponse && !shodanResponse.error) {
    shodanData = {
      openPorts: shodanResponse.ports || [],
      vulns: Object.keys(shodanResponse.vulns || {}),
      hostnames: shodanResponse.hostnames || [],
      os: shodanResponse.os || 'Unknown',
      org: shodanResponse.org || 'Unknown',
      isp: shodanResponse.isp || 'Unknown'
    };
  }
} catch (e) { console.log('Shodan parse error:', e.message); }

// Calculate composite threat score (0-100)
const vtScore = virusTotalData.totalEngines > 0
  ? Math.round((virusTotalData.maliciousVotes / virusTotalData.totalEngines) * 40)
  : 0;
const abuseScore = Math.round((abuseIPData.abuseConfidenceScore / 100) * 35);
const shodanScore = Math.min(shodanData.vulns.length * 5 + shodanData.openPorts.length * 0.5, 25);
const compositeThreatScore = Math.min(Math.round(vtScore + abuseScore + shodanScore), 100);

return {
  json: {
    incident,
    threatIntelligence: {
      virusTotal: virusTotalData,
      abuseIPDB: abuseIPData,
      shodan: shodanData,
      compositeThreatScore,
      enrichedAt: new Date().toISOString()
    }
  }
};

