const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle content array format from Anthropic
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip markdown code blocks if present
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let assessment;
try {
  assessment = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude AI response: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Pull enriched incident from upstream
const enrichedData = $('Combine Enrichment Data').item.json;

// Determine auto-containment flag (Critical or High non-false-positive)
const autoContain = ['CRITICAL', 'HIGH'].includes(assessment.severity) && !assessment.isFalsePositive;

// Determine notification level
const notifyLevel = {
  'CRITICAL': 'P1_IMMEDIATE',
  'HIGH': 'P2_URGENT',
  'MEDIUM': 'P3_STANDARD',
  'LOW': 'P4_INFORMATIONAL'
}[assessment.severity] || 'P3_STANDARD';

return {
  json: {
    incident: enrichedData.incident,
    threatIntelligence: enrichedData.threatIntelligence,
    assessment,
    responseDecision: {
      autoContain,
      notifyLevel,
      createTicket: true,
      requiresEscalation: assessment.escalateToManagement || assessment.severity === 'CRITICAL',
      requiresForensics: assessment.requiresForensics || false
    },
    assessedAt: new Date().toISOString()
  }
};

