const data = $('Parse AI Assessment').item.json;
const slackResponse = $('Notify SOC Team on Slack').item.json;
const jiraResponse = $('Create Incident Ticket in Jira').item.json;

// Extract Jira ticket key
const jiraTicketKey = jiraResponse?.key || jiraResponse?.id || 'TICKET_CREATION_FAILED';
const jiraTicketUrl = jiraResponse?.key
  ? `https://YOUR_JIRA_DOMAIN.atlassian.net/browse/${jiraResponse.key}`
  : null;

// Containment summary
const containmentActions = [];
if (data.responseDecision.autoContain) {
  if (data.incident.sourceIP) containmentActions.push('IP blocked on firewall');
  if (data.incident.affectedHost) containmentActions.push('Host isolated via EDR');
  if (data.incident.affectedUser) containmentActions.push('User sessions revoked');
}

const report = {
  success: true,
  incidentId: data.incident.incidentId,
  severity: data.assessment.severity,
  severityScore: data.assessment.severityScore,
  confidence: data.assessment.confidence,
  alertType: data.incident.alertType,
  source: data.incident.source,
  summary: data.assessment.summary,
  affectedAssets: {
    host: data.incident.affectedHost,
    user: data.incident.affectedUser,
    sourceIP: data.incident.sourceIP,
    destinationIP: data.incident.destinationIP
  },
  threatIntelligence: {
    compositeThreatScore: data.threatIntelligence.compositeThreatScore,
    virusTotalMalicious: data.threatIntelligence.virusTotal.maliciousVotes,
    abuseConfidenceScore: data.threatIntelligence.abuseIPDB.abuseConfidenceScore,
    knownVulnerabilities: data.threatIntelligence.shodan.vulns
  },
  containment: {
    autoContainmentExecuted: data.responseDecision.autoContain,
    actionsExecuted: containmentActions
  },
  response: {
    jiraTicket: jiraTicketKey,
    jiraTicketUrl,
    slackNotified: !slackResponse?.error,
    notificationLevel: data.responseDecision.notifyLevel
  },
  playbook: data.assessment.recommendedPlaybook,
  mitreTechniques: data.assessment.mitreTechniques,
  iocList: data.assessment.iocList,
  immediateActions: data.assessment.immediateActions,
  investigationSteps: data.assessment.investigationSteps,
  escalateToManagement: data.responseDecision.requiresEscalation,
  requiresForensics: data.responseDecision.requiresForensics,
  processedAt: new Date().toISOString()
};

return { json: report };
